const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);

const processClaim = (step: Step, policies: Policy[]): { payout: number; remainingCap: number } => {
  const policy = policies[step.policy ?? 0];
  const damages = step.incident?.damages ?? [];
  const totalDamage = damages.reduce((sum, d) => sum + d.amount, 0);
  const payout = Math.floor(totalDamage - DEDUCTIBLE);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (input: unknown): unknown => {
  const { customer, steps } = input as Input;
  let quoteIndex = 0;
  const policies: Policy[] = [];
  const results = steps.map((step) => {
    if (step.op === "quote") {
      const items = step.items ?? [];
      const premium = quotePremium({ op: step.op, items }, customer, quoteIndex);
      quoteIndex++;
      policies.push({ items, remainingCap: 2 * insuranceSum(items) });
      return { premium };
    }
    return processClaim(step, policies);
  });
  return { results };
};
